    [EntityBehaviourDefinition(VanillaEnemyNames.KogasaZombie)]
    public class KogasaZombie : Zombie
    {
        public KogasaZombie(string nsp, string name) : base(nsp, name)
        {
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            // 在近战攻击状态时，对目标施加蚀毒  
            if (entity.State == STATE_MELEE_ATTACK)
            {
                var targetID = EnemyMeleeBehaviour.GetMeleeTarget(entity);
                var target = targetID?.GetEntity(entity.Level);
                if (target != null && !target.IsDead)
                {
                    // 参数: 每帧伤害1.0, 持续150帧(5秒), 来源为自身  
                    //target.InflictCorropoisonBuff(1f, 150, new EntitySourceReference(entity));
                    target.Stun(150);
                }
            }
        }
        public const int STATE_MELEE_ATTACK = VanillaEnemyStates.MELEE_ATTACK;    
